package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testGetTrim() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        // Given
        CSVFormat csvFormat = new CSVFormat(',', '"', QuoteMode.ALL, '#', '\\', true, false, "\r\n",
                "\\N", new Object[]{"Header"}, new String[]{"header1", "header2"}, true, false, true, true, false);

        // When
        Method method = CSVFormat.class.getDeclaredMethod("getTrim");
        method.setAccessible(true);
        boolean result = (boolean) method.invoke(csvFormat);

        // Then
        assertTrue(result);
    }
}
